    "# Evaluation metrics (test set)\n",
    "def print_binary_metrics(name, y_true, y_pred, y_proba):\n",
    " print(f\"\\n{'='*50}\")\n",
    " print(f\" {name}\")\n",
    " print(f\"{'='*50}\")\n",
